={{ JSON.stringify(
  (() => {
    // Bases
    const fx = $node["fluxo_chamado"].json.body.payload || {};
    const pu = $node["pesquisa_user1"].json || {};

    const contactId  = $node["pesquisa_user1"].json.id_contact_crm;

    // Helper para pegar primeiro valor definido
    const firstOf = (...vals) => vals.find(v => v !== undefined && v !== null) ?? null;

    const status = firstOf(
      $node["pesquisa_json_fields_deal4"]?.runIndex  >= 0 ? $node["pesquisa_json_fields_deal4"].json.status  : undefined,
      $node["pesquisa_json_fields_deal5"]?.runIndex >= 0 ? $node["pesquisa_json_fields_deal5"].json.status : undefined,
      $node["pesquisa_json_fields_deal6"]?.runIndex >= 0 ? $node["pesquisa_json_fields_deal6"].json.status : undefined,
      $node["pesquisa_json_fields_deal7"]?.runIndex >= 0 ? $node["pesquisa_json_fields_deal7"].json.status : undefined,
      null
    );

    // Nome completo com fallback
    const firstName = fx.nome ?? pu.nome ?? "";
    const lastName  = fx.sobrenome ?? pu.sobrenome ?? "";
    const name = `${firstName}${lastName ? " " + lastName : ""}`.trim();

    // ---- customFields: pegar primeiro array NÃO vazio entre os nodes ----
    const nonEmpty = v => Array.isArray(v) && v.length > 0;

    const getCF = (nodeName) => {
      if ($node[nodeName]?.runIndex >= 0) {
        const viaItems = $items(nodeName, 0)?.json?.custom_fields_values;
        if (nonEmpty(viaItems)) return viaItems;

        const viaNode = $node[nodeName]?.json?.custom_fields_values;
        if (nonEmpty(viaNode)) return viaNode;
      }
      return null;
    };

    const cf =
      getCF("formata_campos_deal4")  ||
      getCF("formata_campos_deal5") ||
      getCF("formata_campos_deal6") ||
      getCF("formata_campos_deal7") ||
      null;

    // Monta body (sem assignedTo, sem pipelineId/pipelineStageId)
    const body = {
      contactId,
      status,
      name,
    };

    if (cf) body.customFields = cf;

    return body;
  })()
) }}

